 1→import React, { useEffect, useState } from 'react';
 2→import { motion, AnimatePresence } from 'framer-motion';
 3→import './StreakMilestoneToast.css';
 4→
 5→const milestoneMessages = {
 6→    7: "1 week streak! You're on fire!",
 7→    14: "2 weeks strong! Unstoppable!",
 8→    30: "30 days! A whole month of writing!",
 9→    50: "50 day streak! Legend in the making!",
10→    100: "100 DAYS! Absolute legend!",
11→};
12→
13→const StreakMilestoneToast = ({ milestone, onDismiss }) => {
14→    const [confettiPieces, setConfettiPieces] = useState([]);
15→
16→    useEffect(() => {
17→        if (!milestone) return;
18→
19→        // Generate confetti pieces
20→        const pieces = Array.from({ length: 24 }, (_, i) => ({
21→            id: i,
22→            x: Math.random() * 100,
23→            delay: Math.random() * 0.5,
24→            duration: 1.5 + Math.random() * 1,
25→            color: ['#f59e0b', '#ef4444', '#f97316', '#eab308', '#22c55e', '#3b82f6'][i % 6],
26→            rotation: Math.random() * 360,
27→        }));
28→        setConfettiPieces(pieces);
29→
30→        const timer = setTimeout(() => {
31→            onDismiss?.();
32→        }, 5000);
33→
34→        return () => clearTimeout(timer);
35→    }, [milestone, onDismiss]);
36→
37→    if (!milestone) return null;
38→
39→    return (
40→        <AnimatePresence>
41→            <motion.div
42→                className="streak-milestone-toast"
43→                initial={{ opacity: 0, y: 60, scale: 0.9 }}
44→                animate={{ opacity: 1, y: 0, scale: 1 }}
45→                exit={{ opacity: 0, y: -20, scale: 0.95 }}
46→                transition={{ type: 'spring', damping: 20, stiffness: 300 }}
47→                onClick={onDismiss}
48→            >
49→                <div className="streak-milestone-confetti">
50→                    {confettiPieces.map((piece) => (
51→                        <motion.div
52→                            key={piece.id}
53→                            className="confetti-piece"
54→                            style={{
55→                                left: `${piece.x}%`,
56→                                backgroundColor: piece.color,
57→                            }}
58→                            initial={{ y: -10, opacity: 1, rotate: 0 }}
59→                            animate={{
60→                                y: 120,
61→                                opacity: 0,
62→                                rotate: piece.rotation,
63→                            }}
64→                            transition={{
65→                                duration: piece.duration,
66→                                delay: piece.delay,
67→                                ease: 'easeOut',
68→                            }}
69→                        />
70→                    ))}
71→                </div>
72→                <div className="streak-milestone-content">
73→                    <span className="streak-milestone-flame">
74→                        <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 -960 960 960" fill="#eab308">
75→                            <path d="M80-120q27-71 65-133.5T225-370q-10-26-15-52t-5-54q0-94 55-168.5T400-740q-3 42 10 81t38 72q25 33 60.5 52t77.5 22q-6-39 2-77.5t28-72.5q20-34 49.5-61T726-776q-2 48 8 93.5t31 86.5q21 41 33 85t12 91q0 30-5 58.5T790-308q10 10 19 20.5t18 21.5q31 38 55 80t43 86H80Z" />
76→                        </svg>
77→                    </span>
78→                    <div className="streak-milestone-text">
79→                        <span className="streak-milestone-count">{milestone} Day Streak!</span>
80→                        <span className="streak-milestone-msg">{milestoneMessages[milestone]}</span>
81→                    </div>
82→                </div>
83→            </motion.div>
84→        </AnimatePresence>
85→    );
86→};
87→
88→export default StreakMilestoneToast;
