  1→import React, { useState } from 'react';
  2→import { useQuery } from '@tanstack/react-query';
  3→import { motion, AnimatePresence } from 'framer-motion';
  4→import { getWeeklyRecap, getTodaysPrompt, getPromptResponses } from '../../../API/Api';
  5→import { useAuth } from '../../Context/useAuth';
  6→import useStreakData from '../Streak/useStreakData';
  7→import StreakBadge from '../Streak/StreakBadge';
  8→import RecapSection from './RecapSection';
  9→import PromptSection from './PromptSection';
 10→import './DashboardBriefing.css';
 11→
 12→const getWeekKey = () => {
 13→    const now = new Date();
 14→    const day = now.getUTCDay();
 15→    const diff = day === 0 ? 6 : day - 1;
 16→    const monday = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate() - diff));
 17→    return `recap-dismissed-${monday.toISOString().slice(0, 10)}`;
 18→};
 19→
 20→const formatDate = () => {
 21→    return new Date().toLocaleDateString('en-US', {
 22→        weekday: 'long',
 23→        month: 'long',
 24→        day: 'numeric',
 25→    });
 26→};
 27→
 28→const DashboardBriefing = ({ onWriteResponse }) => {
 29→    const { session, user } = useAuth();
 30→    const weekKey = getWeekKey();
 31→
 32→    const [recapCollapsed, setRecapCollapsed] = useState(() => {
 33→        try { return localStorage.getItem(weekKey) === 'true'; }
 34→        catch { return false; }
 35→    });
 36→
 37→    // ─── Data fetching ───
 38→
 39→    const { data: recapData, isLoading: recapLoading } = useQuery({
 40→        queryKey: ['weeklyRecap', session?.access_token],
 41→        queryFn: () => getWeeklyRecap(session?.access_token),
 42→        enabled: !!session?.access_token,
 43→        staleTime: 1000 * 60 * 10,
 44→        refetchOnWindowFocus: false,
 45→    });
 46→
 47→    const { data: prompt, isLoading: promptLoading } = useQuery({
 48→        queryKey: ['todaysPrompt'],
 49→        queryFn: getTodaysPrompt,
 50→        staleTime: 1000 * 60 * 30,
 51→        refetchOnWindowFocus: false,
 52→    });
 53→
 54→    const { data: responsesData } = useQuery({
 55→        queryKey: ['promptResponses', prompt?.id],
 56→        queryFn: () => getPromptResponses(prompt.id),
 57→        enabled: !!prompt?.id,
 58→        staleTime: 1000 * 60 * 5,
 59→        refetchOnWindowFocus: false,
 60→    });
 61→
 62→    const { data: streakData } = useStreakData(user?.id);
 63→
 64→    // ─── Derived state ───
 65→
 66→    const recap = recapData?.recap;
 67→    const personal = recap?.personal || {};
 68→    const group = recap?.group || {};
 69→
 70→    const hasRecap = !recapLoading && recap &&
 71→        (personal.posts_written > 0 || group.total_posts > 0);
 72→    const hasPrompt = !promptLoading && !!prompt;
 73→
 74→    // Nothing to show
 75→    if (!hasRecap && !hasPrompt) return null;
 76→
 77→    const handleToggleRecap = (e) => {
 78→        e.stopPropagation();
 79→        const next = !recapCollapsed;
 80→        try { localStorage.setItem(weekKey, next ? 'true' : 'false'); }
 81→        catch { /* no-op */ }
 82→        setRecapCollapsed(next);
 83→    };
 84→
 85→    const streakCount = streakData?.current_streak || 0;
 86→
 87→    return (
 88→        <AnimatePresence>
 89→            <motion.div
 90→                className="dashboard-briefing"
 91→                initial={{ opacity: 0, y: -10 }}
 92→                animate={{ opacity: 1, y: 0 }}
 93→                exit={{ opacity: 0, y: -15, transition: { duration: 0.25 } }}
 94→                transition={{ duration: 0.35, ease: 'easeOut' }}
 95→                key="dashboard-briefing"
 96→            >
 97→                <div className="dashboard-briefing-header">
 98→                    <div className="dashboard-briefing-header-left">
 99→                        <span className="dashboard-briefing-title">Today</span>
100→                        <span className="dashboard-briefing-date">{formatDate()}</span>
101→                        {streakCount > 0 && <StreakBadge count={streakCount} size={14} showProgress freezeAvailable={streakData?.freeze_available} />}
102→                    </div>
103→                    {hasRecap && (
104→                        <button
105→                            className={`dashboard-briefing-toggle ${recapCollapsed ? 'is-collapsed' : ''}`}
106→                            onClick={handleToggleRecap}
107→                            title={recapCollapsed ? 'Show stats' : 'Hide stats'}
108→                        >
109→                            <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
110→                                <path d="M6 9L12 15L18 9" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
111→                            </svg>
112→                        </button>
113→                    )}
114→                </div>
115→
116→                <div className="dashboard-briefing-body">
117→                    <AnimatePresence initial={false}>
118→                        {hasRecap && !recapCollapsed && (
119→                            <motion.div
120→                                key="recap"
121→                                initial={{ height: 0, opacity: 0 }}
122→                                animate={{ height: 'auto', opacity: 1 }}
123→                                exit={{ height: 0, opacity: 0 }}
124→                                transition={{ duration: 0.25, ease: 'easeOut' }}
125→                                style={{ overflow: 'hidden' }}
126→                            >
127→                                <RecapSection personal={personal} group={group} streakCount={streakCount} freezeAvailable={streakData?.freeze_available} />
128→                            </motion.div>
129→                        )}
130→                    </AnimatePresence>
131→
132→                    {hasRecap && hasPrompt && !recapCollapsed && (
133→                        <div className="dashboard-divider" />
134→                    )}
135→
136→                    {hasPrompt && (
137→                        <PromptSection
138→                            prompt={prompt}
139→                            responsesData={responsesData}
140→                            onWriteResponse={onWriteResponse}
141→                        />
142→                    )}
143→                </div>
144→            </motion.div>
145→        </AnimatePresence>
146→    );
147→};
148→
149→export default DashboardBriefing;
